    lda l0df0,y                                                       ; 8cb0: b9 f0 0d    ...            ; Load workspace page for this slot
    tay                                                               ; 8cb3: a8          .              ; Transfer to Y
    rts                                                               ; 8cb4: 60          `              ; Return with page in A and Y

